 	if len(refs) == 0 {
 		return
 	}
 	cmd := exec.Command(
 		"git", append([]string{"-C", repoDir, "push", "origin"},
 			refspecs(refs)...)...,
 	)
 	cmd.Env = pushEnv()
 	detach(cmd)
 	if cmd.Start() == nil {
 		_ = cmd.Process.Release()
 	}
