 // backfilled commit) appended after the fixed machine identity.
 func gitInEnv(
 	dir string, stdin io.Reader, env []string, args ...string,
 ) (string, error) {
 	cmd := exec.Command("git", append([]string{"-C", dir}, args...)...)
 	cmd.Stdin = stdin
 	cmd.Env = append(os.Environ(),
 		"GIT_AUTHOR_NAME=wasa",
 		"GIT_AUTHOR_EMAIL=wasa@localhost",
 		"GIT_COMMITTER_NAME=wasa",
 		"GIT_COMMITTER_EMAIL=wasa@localhost",
 	)
 	cmd.Env = append(cmd.Env, env...)
 	var stdout, stderr bytes.Buffer
 	cmd.Stdout = &stdout
 	cmd.Stderr = &stderr
 	if err := cmd.Run(); err != nil {
 		msg := strings.TrimSpace(stderr.String())
 		if msg == "" {
 			return "", fmt.Errorf("git %s: %w", strings.Join(args, " "), err)
 		}
 		return "", fmt.Errorf(
 			"git %s: %w: %s", strings.Join(args, " "), err, msg,
 		)
