 // none (empty repository) or dir is not a repository.
 func headSHA(repoDir string) string {
 	sha, _ := gitIn(
 		repoDir,
 		nil,
 		"rev-parse",
 		"--verify",
 		"-q",
 		"HEAD^{commit}",
 	)
 	return sha
 }

