 // oldHead, oldest first. An empty oldHead lists everything up to newHead.
 func commitsBetween(repoDir, oldHead, newHead string) []string {
 	rng := newHead
 	if oldHead != "" {
 		rng = oldHead + ".." + newHead
 	}
 	out, err := gitIn(repoDir, nil, "rev-list", "--reverse", rng)
 	if err != nil || out == "" {
 		return nil
 	}
 	return strings.Fields(out)
