221. // refInfo is one checkpoint ref as reported by for-each-ref.
222. type refInfo struct {
223. 	ref     string
224. 	id      string
225. 	sha     string
226. 	when    time.Time
227. 	session string
228. }
229. 
230. // forEachRef lists every checkpoint ref, newest first. Ordering is by the
231. // ULID (the ref's leaf), which is timestamp-prefixed and so sorts
232. // chronologically; the full refname cannot be used because the shard segment
233. // — the ULID's last two characters — precedes the ULID in the path and would
234. // scramble the order. A repository with no checkpoint ref yields nil, nil: no
235. // record is a normal state, not an error.
236. func forEachRef(repoDir string) ([]refInfo, error) {
237. 	out, err := gitIn(
238. 		repoDir, nil, "for-each-ref",
239. 		"--format=%(refname)\x1f%(objectname)\x1f%(committerdate:unix)"+
240. 			"\x1f%(contents:subject)",
241. 		RefPrefix+"/",
242. 	)
243. 	if err != nil || out == "" {
244. 		return nil, nil
245. 	}
246. 	var refs []refInfo
247. 	for raw := range strings.SplitSeq(out, "\n") {
248. 		parts := strings.SplitN(strings.TrimSpace(raw), "\x1f", 4)
249. 		if len(parts) != 4 {
250. 			continue
251. 		}
252. 		ts, _ := strconv.ParseInt(parts[2], 10, 64)
253. 		ref := parts[0]
254. 		refs = append(refs, refInfo{
255. 			ref:     ref,
256. 			id:      ref[strings.LastIndexByte(ref, '/')+1:],
257. 			sha:     parts[1],
258. 			when:    time.Unix(ts, 0),
259. 			session: parts[3],
260. 		})
261. 	}
262. 	slices.SortFunc(refs, func(a, b refInfo) int {
263. 		return strings.Compare(b.id, a.id)
264. 	})
265. 	return refs, nil
266. }
