268. // readEntry loads a checkpoint's meta.json, degrading to the subject-derived
269. // session id when the blob is missing or malformed.
270. func readEntry(repoDir string, r refInfo) Entry {
271. 	e := Entry{Ref: r.ref, ID: r.id, CommitSHA: r.sha, When: r.when}
272. 	e.Meta.SessionID = r.session
273. 	if raw, err := gitIn(
274. 		repoDir, nil, "show", r.sha+":meta.json",
275. 	); err == nil {
276. 		var m Meta
277. 		if json.Unmarshal([]byte(raw), &m) == nil && m.SessionID != "" {
278. 			e.Meta = m
279. 		}
280. 	}
281. 	return e
282. }
