 			id:      ref[strings.LastIndexByte(ref, '/')+1:],
 			sha:     parts[1],
 			when:    time.Unix(ts, 0),
 			session: parts[3],
 		})
 	}
 	slices.SortFunc(refs, func(a, b refInfo) int {
 		return strings.Compare(b.id, a.id)
 	})
 	return refs, nil
