 		repoDir, nil, "show", r.sha+":meta.json",
 	); err == nil {
 		var m Meta
 		if json.Unmarshal([]byte(raw), &m) == nil && m.SessionID != "" {
 			e.Meta = m
 		}
 	}
 	return e
 }

