128. func Finalize(home, sid string) error {
129. 	st, ok := loadState(home, sid)
130. 	if !ok || st.RepoDir == "" {
131. 		return nil
132. 	}
133. 	if head := headSHA(st.RepoDir); head != "" && head != st.LastHead {
134. 		st = checkpointNewCommits(st.RepoDir, st, head)
135. 	}
136. 	native, _ := os.ReadFile(st.TranscriptPath)
137. 	m := st.meta()
138. 	m.FinishedAt = time.Now()
139. 	if len(native) == 0 {
140. 		m.Gaps = append(m.Gaps, "transcript unavailable")
141. 	}
142. 	ref, err := Write(st.RepoDir, Checkpoint{
143. 		Meta: m, Intent: st.Intent, Transcript: normalize(st.Agent, native),
144. 	})
145. 	if err != nil {
146. 		return err
147. 	}
148. 	removeState(home, sid)
149. 	pushDetached(st.RepoDir, []string{ref})
150. 	return nil
151. }
152. 
153. // newState seeds the recording state the first time a session is seen. A
154. // managed session is enriched from the registry, which knows its workspace,
155. // branch and base commit authoritatively; an unmanaged session gets what git
156. // can tell about the directory it runs in.
157. func newState(home, sid, repoDir string, ev Event) state {
158. 	st := state{
159. 		SessionID:  sid,
160. 		RepoDir:    repoDir,
161. 		Agent:      ev.Agent,
162. 		Branch:     headBranch(repoDir),
163. 		BaseCommit: headSHA(repoDir),
164. 		Unmanaged:  ev.WasaSession == "",
165. 		StartedAt:  time.Now(),
166. 	}
167. 	st.LastHead = st.BaseCommit
168. 	if st.Unmanaged {
169. 		return st
170. 	}
171. 	reg, err := registry.Open(home)
172. 	if err != nil {
173. 		return st
174. 	}
175. 	s, ok := reg.Session(sid)
176. 	if !ok {
177. 		return st
178. 	}
179. 	st.WorkspaceID = s.WorkspaceID
180. 	st.ResumedFrom = s.ResumedFrom
181. 	if s.Branch != "" {
182. 		st.Branch = s.Branch
183. 	}
184. 	if s.BaseCommit != "" {
185. 		st.BaseCommit = s.BaseCommit
186. 	}
187. 	if !s.CreatedAt.IsZero() {
188. 		st.StartedAt = s.CreatedAt
189. 	}
190. 	return st
191. }
192. 
193. // checkpointNewCommits writes one commit-linked checkpoint per commit that
194. // landed since the state's last look at HEAD, collapsing a burst larger than
195. // commitBurstLimit into a single checkpoint so a pull or rebase cannot flood
196. // the ref. Checkpoint failures are skipped silently per the degradation
197. // contract; the head is still advanced so the same commits are not retried
198. // on every subsequent event.
199. func checkpointNewCommits(repoDir string, st state, head string) state {
200. 	newCommits := commitsBetween(repoDir, st.LastHead, head)
201. 	if len(newCommits) == 0 {
202. 		st.LastHead = head
203. 		return st
204. 	}
205. 	native, _ := os.ReadFile(st.TranscriptPath)
206. 	transcript := normalize(st.Agent, native)
207. 
208. 	var burst []string
209. 	if len(newCommits) > commitBurstLimit {
210. 		burst = newCommits[:len(newCommits)-1]
211. 		newCommits = newCommits[len(newCommits)-1:]
212. 	}
213. 	st.Commits = append(st.Commits, burst...)
214. 	var refs []string
215. 	for _, c := range newCommits {
216. 		st.Commits = append(st.Commits, c)
217. 		m := st.meta()
218. 		m.Commit = c
219. 		if len(burst) > 0 {
220. 			m.Gaps = append(m.Gaps, fmt.Sprintf(
221. 				"%d commits arrived at once; only the newest is linked",
222. 				len(burst)+1,
223. 			))
224. 		}
225. 		if len(native) == 0 {
226. 			m.Gaps = append(m.Gaps, "transcript unavailable")
227. 		}
228. 		if ref, err := Write(repoDir, Checkpoint{
229. 			Meta: m, Intent: st.Intent, Transcript: transcript,
230. 		}); err == nil {
231. 			refs = append(refs, ref)
232. 		}
233. 	}
234. 	st.LastHead = head
235. 	pushDetached(repoDir, refs)
236. 	return st
237. }
238. 
239. // FinishInfo describes a finishing session as the teardown flow knows it.
240. // Every field is optional except SessionID; whatever the finish flow does
241. // not know is filled from the recorded state, and what neither knows is
242. // noted as a gap.
243. type FinishInfo struct {
244. 	SessionID   string
245. 	WorkspaceID string
246. 	// Program is the launch program; its base executable is recorded as the
247. 	// agent.
248. 	Program    string
249. 	Branch     string
250. 	BaseCommit string
251. 	// RepoDir is the repository the session ran against.
252. 	RepoDir   string
253. 	StartedAt time.Time
254. 	// ResumedFrom is the session id this session was resumed from, empty when
255. 	// the session started fresh.
256. 	ResumedFrom string
257. }
258. 
259. // Finish writes a session's closing checkpoint: the final transcript, the
260. // full commit list and the finish timestamp. A session that produced zero
261. // commits is still recorded — failed attempts are history worth keeping. It
262. // returns at most one error for the caller to log; teardown must never act
263. // on it. A session with no known repository (a plain session outside any
264. // repo, with no hook data) records nothing and returns nil.
265. func Finish(home string, info FinishInfo) error {
266. 	if info.SessionID == "" {
267. 		return nil
268. 	}
269. 	st, hasState := loadState(home, info.SessionID)
270. 
271. 	repoDir := info.RepoDir
272. 	if repoDir == "" {
273. 		repoDir = st.RepoDir
274. 	}
275. 	if repoDir == "" {
276. 		return nil
277. 	}
278. 
279. 	m := st.meta()
280. 	m.SessionID = info.SessionID
281. 	m.Unmanaged = false
282. 	if info.WorkspaceID != "" {
283. 		m.WorkspaceID = info.WorkspaceID
284. 	}
285. 	if agent := baseExe(info.Program); agent != "" {
286. 		m.Agent = agent
287. 	}
288. 	if info.Branch != "" {
289. 		m.Branch = info.Branch
290. 	}
291. 	if info.BaseCommit != "" {
