 func showCheckpoint(repoPath string, args []string, jsonOut bool) error {
 	fs := newFlagSet("wasa checkpoints show")
 	asJSON := jsonFlag(fs)
 	flags, positional := partitionArgs(args, nil)
 	if err := fs.Parse(flags); err != nil {
 		return err
 	}
 	if len(positional) != 1 {
 		return errors.New("usage: wasa checkpoints show [--json] <id>")
 	}
 	jsonOut = jsonOut || *asJSON
 	query := positional[0]

 	e, intent, transcript, err := record.Find(repoPath, query)
 	if err != nil {
 		return err
 	}

 	if jsonOut {
 		item := checkpointJSON{
 			Meta:      e.Meta,
 			CommitSHA: e.CommitSHA,
 			When:      e.When,
 			State:     checkpointState(e.Meta),
 			Intent:    intent,
 		}
 		if len(transcript) != 0 {
 			item.Transcript = record.RenderTranscript(transcript)
 		}
 		return emitJSON(os.Stdout, item)
 	}

 	meta, err := json.MarshalIndent(e.Meta, "", "  ")
 	if err != nil {
 		return err
 	}
 	fmt.Fprintf(os.Stdout, "session %s (checkpoint %s)\n\n",
 		e.Meta.SessionID, e.CommitSHA)
 	fmt.Fprintf(os.Stdout, "intent:\n%s\n\n", indent(intent))
 	fmt.Fprintf(os.Stdout, "meta:\n%s\n\n", indent(string(meta)))
 	if len(transcript) == 0 {
 		fmt.Fprintln(os.Stdout, "transcript: (not captured)")

